using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.InputSystem;
using UnityEngine.UI;

/// <summary>
/// Sub-painel "Jukebox" — lista de faixas organizada por mundo, com aba de
/// Favoritos (L/R), disco giratório na faixa activa e persistência de favoritos
/// via <see cref="GameVariables"/>.
///
/// ────────────────────────────────────────────────────────────────────────────
/// <b>ESTRUTURA DA UI (montar no Editor):</b>
///
/// JukeboxSectionUI (MonoBehaviour + AudioSource)
///   ├── Root (GameObject — activado/desactivado em Open/Close)
///   │     ├── TabBar
///   │     │     ├── NormalTabHighlight    ← activo na aba Normal
///   │     │     └── FavoritesTabHighlight ← activo na aba Favoritos
///   │     ├── ScrollView → Content (trackContainer)
///   │     │     └── [instanciado: SectionHeaderPrefab e TrackButtonPrefab]
///   │     ├── NowPlayingText (TMP_Text)
///   │     └── BackButton (Button)
///   └── LockedRoot (GameObject — mostrado antes da compra)
///         ├── LockedMessageText (TMP_Text)
///         └── LockedBackButton (Button)
///
/// ────────────────────────────────────────────────────────────────────────────
/// <b>SECÇÕES POR MUNDO:</b>
/// • Faixas estáticas (<see cref="tracks"/>) com <c>world == null</c> →
///   agrupadas numa secção com <see cref="staticSectionLabel"/> (ex: "Trilha Sonora").
/// • Faixas estáticas com <c>world != null</c> → agrupadas com as wild melodies
///   desse mundo.
/// • Wild melodies → agrupadas por <c>WildMelodyData.area.world</c>;
///   sem área/mundo → secção <see cref="unknownSectionLabel"/> (ex: "Outras Melodias").
///
/// ────────────────────────────────────────────────────────────────────────────
/// <b>ABAS:</b>
/// • L (tabPrevAction) → aba Normal.
/// • R (tabNextAction) → aba Favoritos.
/// • B (backButton / cancelAction) → fecha o painel.
///
/// ────────────────────────────────────────────────────────────────────────────
/// <b>FAVORITOS:</b>
/// Guardados em <see cref="GameVariables"/> como booleans com chave
/// <c>"jukebox_fav_&lt;id&gt;"</c> — persistidos automaticamente no save.
/// </summary>
[RequireComponent(typeof(AudioSource))]
public class JukeboxSectionUI : MonoBehaviour, ICancelHandler
{
    // ═══════════════════════════════════════════════════════════════════════
    // Tipos internos
    // ═══════════════════════════════════════════════════════════════════════

    /// <summary>Faixa estática configurada no Inspector.</summary>
    [System.Serializable]
    public class JukeboxTrack
    {
        [Tooltip("Clip de áudio.")]
        public AudioClip clip;

        [Tooltip("Nome mostrado na lista. Se vazio, usa o nome do clip.")]
        public string displayName;

        [Tooltip("Mundo a que esta faixa pertence — agrupa-a com as wild melodies desse mundo. Deixar vazio para a secção de trilha sonora base.")]
        public WorldData world;

        [Tooltip(
            "ID de melodia para desbloqueio individual. Se preenchido, a faixa só aparece quando " +
            "PlayerProgress.HasCollectedMelody(melodyId) for true (ex: encontrada num WildMelodyPickup). " +
            "Deixar VAZIO para faixas sempre visíveis após comprar o Jukebox (trilha sonora base).")]
        public string melodyId;

        public string GetDisplayName() =>
            string.IsNullOrEmpty(displayName) && clip != null ? clip.name : displayName;

        /// <summary>
        /// Chave estável para favoritos.
        /// Se <see cref="melodyId"/> estiver preenchido usa-o directamente (mesma chave que o
        /// <see cref="WildMelodyData"/> correspondente).
        /// Caso contrário deriva a chave do nome da faixa.
        /// </summary>
        public string GetId()
        {
            if (!string.IsNullOrEmpty(melodyId)) return melodyId;
            string raw = string.IsNullOrEmpty(displayName)
                ? (clip != null ? clip.name : displayName)
                : displayName;
            return "static_" + raw.ToLowerInvariant().Replace(" ", "_");
        }
    }

    /// <summary>Entrada interna da lista de exibição (faixa estática ou wild melody).</summary>
    private sealed class DisplayEntry
    {
        /// <summary>Chave estável para GameVariables de favoritos.</summary>
        public string id;
        public AudioClip clip;
        public string name;
        /// <summary>Mundo desta faixa (null = trilha sonora base ou sem mundo).</summary>
        public WorldData world;
    }

    private enum JukeboxTab { Normal, Favorites }

    // ═══════════════════════════════════════════════════════════════════════
    // Inspector
    // ═══════════════════════════════════════════════════════════════════════

    [Header("Desbloqueio por Compra na Loja")]
    [SerializeField] private ItemData jukeboxItem;
    [SerializeField] private GameObject lockedRoot;
    [SerializeField] private TMP_Text lockedMessageText;
    [SerializeField] private string lockedMessage = "Compra o Jukebox numa loja para desbloqueá-lo!";
    [SerializeField] private Button lockedBackButton;

    [Header("Faixas Estáticas")]
    [Tooltip("Trilha sonora base. Cada faixa pode ser associada a um WorldData para aparecer na secção desse mundo.")]
    [SerializeField] private List<JukeboxTrack> tracks = new List<JukeboxTrack>();

    [Header("Melodias Selvagens")]
    [Tooltip("Todos os WildMelodyData do jogo — o Jukebox filtra as já recolhidas.")]
    [SerializeField] private List<WildMelodyData> knownMelodies = new List<WildMelodyData>();

    [Header("Secções")]
    [Tooltip("Etiqueta da secção para faixas estáticas sem mundo.")]
    [SerializeField] private string staticSectionLabel = "Trilha Sonora";
    [Tooltip("Etiqueta da secção para wild melodies sem área/mundo definido.")]
    [SerializeField] private string unknownSectionLabel = "Outras Melodias";
    [Tooltip("Etiqueta da aba de Favoritos (usada como título de secção quando a aba está activa).")]
    [SerializeField] private string favoritesSectionLabel = "Favoritos";

    [Header("Prefabs")]
    [SerializeField] private JukeboxTrackButtonUI trackButtonPrefab;
    [Tooltip("Prefab de cabeçalho de secção — deve ter um TMP_Text no GameObject raiz ou num filho chamado 'Label'.")]
    [SerializeField] private GameObject sectionHeaderPrefab;

    [Header("Framework")]
    [SerializeField] private GameObject root;
    [SerializeField] private Transform trackContainer;
    [SerializeField] private Selectable firstSelectable;
    [SerializeField] private Button backButton;
    [SerializeField] private TMP_Text nowPlayingText;
    [SerializeField] private string noTracksText = "— sem músicas —";

    [Header("Abas (Tab Bar)")]
    [Tooltip("Highlight/indicador visual da aba Normal (activo quando na aba Normal).")]
    [SerializeField] private GameObject normalTabHighlight;
    [Tooltip("Highlight/indicador visual da aba Favoritos (activo quando na aba Favoritos).")]
    [SerializeField] private GameObject favoritesTabHighlight;

    [Header("Input — Trocar Aba")]
    [Tooltip("Acção que muda para a aba anterior (LB / L1) — volta à aba Normal.")]
    [SerializeField] private InputActionReference tabPrevAction;
    [Tooltip("Acção que muda para a aba seguinte (RB / R1) — vai para Favoritos.")]
    [SerializeField] private InputActionReference tabNextAction;

    [Header("Sons")]
    [SerializeField] private AudioClip toggleSfx;
    [SerializeField] private AudioClip tabSwitchSfx;
    [SerializeField] private AudioClip favoriteSfx;

    // ═══════════════════════════════════════════════════════════════════════
    // Eventos
    // ═══════════════════════════════════════════════════════════════════════

    /// <summary>Disparado ao fechar o painel.</summary>
    public event System.Action Closed;

    /// <summary>
    /// Disparado por <see cref="WildMelodyPickup"/> quando uma Melodia Selvagem é
    /// recolhida — actualiza a lista em tempo real se o Jukebox estiver aberto.
    /// </summary>
    public static event System.Action<WildMelodyData> OnWildMelodyCollected;

    /// <summary>
    /// Dispara <see cref="OnWildMelodyCollected"/> — chamado por
    /// WildMelodyPickup ao recolher uma melodia (eventos C# só podem ser
    /// invocados dentro da classe que os declara).
    /// </summary>
    public static void NotifyMelodyCollected(WildMelodyData melody) => OnWildMelodyCollected?.Invoke(melody);

    // Task #11: limpa subscribers ao entrar em Play Mode sem Domain Reload
    // (mesmo padrão de PlayerLocator/GamePauseUtil/WheelTimeScaleUtil).
    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.SubsystemRegistration)]
    private static void ResetStaticEvents() => OnWildMelodyCollected = null;

    // ═══════════════════════════════════════════════════════════════════════
    // Estado privado
    // ═══════════════════════════════════════════════════════════════════════

    public GameObject Root => root != null ? root : gameObject;

    private AudioSource _source;

    /// <summary>Lista COMPLETA de entradas (todas as faixas recolhidas + estáticas).</summary>
    private readonly List<DisplayEntry> _allEntries = new List<DisplayEntry>();

    /// <summary>Entradas actualmente visíveis na lista (Normal = todas; Favoritos = só favoritas).</summary>
    private readonly List<DisplayEntry> _visibleEntries = new List<DisplayEntry>();

    // Pool de botões e headers (Task #29): nunca destruídos, activados/desactivados.
    // Botões da pool têm Clicked/FavoriteClicked subscritos UMA VEZ (na criação).
    private readonly List<JukeboxTrackButtonUI> _buttonPool  = new List<JukeboxTrackButtonUI>();
    private readonly List<GameObject>           _headerPool  = new List<GameObject>();

    // Botões/headers actualmente visíveis (subconjunto das pools).
    private readonly List<JukeboxTrackButtonUI> _spawned        = new List<JukeboxTrackButtonUI>();
    private readonly List<GameObject>           _spawnedHeaders = new List<GameObject>();

    private int _currentIndex = -1;   // índice em _allEntries da faixa a tocar
    private int _focusIndex   = -1;   // índice em _visibleEntries do botão com foco
    private bool _isPlaying;
    private bool _isOpen;

    // Task — Ownership de BGM: guardamos o clip activo antes de o Jukebox tomar
    // controlo, para restaurar quando parar ou fechar.
    private AudioClip _savedBgmClip;
    private bool _bgmOwned;
    private JukeboxTab _currentTab = JukeboxTab.Normal;

    // Chave GameVariables para favorito de uma entrada
    private static string FavKey(string id) => "jukebox_fav_" + id;

    // ═══════════════════════════════════════════════════════════════════════
    // Unity
    // ═══════════════════════════════════════════════════════════════════════

    private void Awake()
    {
        _source = GetComponent<AudioSource>();
        _source.playOnAwake = false;
        _source.loop = false;

        if (backButton != null)       backButton.onClick.AddListener(Close);
        if (lockedBackButton != null) lockedBackButton.onClick.AddListener(Close);
        if (lockedMessageText != null) lockedMessageText.text = lockedMessage;

        if (root != null)       root.SetActive(false);
        if (lockedRoot != null) lockedRoot.SetActive(false);
    }

    private void OnEnable()
    {
        OnWildMelodyCollected += HandleMelodyCollected;

        if (tabPrevAction != null) tabPrevAction.action.started += OnTabPrev;
        if (tabNextAction != null) tabNextAction.action.started += OnTabNext;

        if (tabPrevAction != null) tabPrevAction.action.Enable();
        if (tabNextAction != null) tabNextAction.action.Enable();
    }

    private void OnDisable()
    {
        OnWildMelodyCollected -= HandleMelodyCollected;

        if (tabPrevAction != null) tabPrevAction.action.started -= OnTabPrev;
        if (tabNextAction != null) tabNextAction.action.started -= OnTabNext;
    }

    private void Update()
    {
        if (_source == null) return;
        ApplyVolume();

        // Avança automaticamente ao terminar a faixa.
        if (_isPlaying && !_source.isPlaying && _allEntries.Count > 0)
        {
            int next = (_currentIndex + 1) % _allEntries.Count;
            PlayEntry(next);
        }
    }

    private void ApplyVolume()
    {
        var audio = AudioManager.Instance;
        _source.volume = audio != null ? audio.BgmVolume * audio.MasterVolume : 1f;
    }

    // ═══════════════════════════════════════════════════════════════════════
    // Abrir / Fechar
    // ═══════════════════════════════════════════════════════════════════════

    public bool IsUnlocked =>
        jukeboxItem == null ||
        (PlayerProgress.Instance?.HasCollectedSpecialItem(jukeboxItem.itemId) ?? false);

    public void Open()
    {
        if (!IsUnlocked)
        {
            if (lockedRoot != null) lockedRoot.SetActive(true);
            if (EventSystem.current != null && lockedBackButton != null)
                EventSystem.current.SetSelectedGameObject(lockedBackButton.gameObject);
            return;
        }

        _isOpen = true;
        _currentTab = JukeboxTab.Normal;

        if (root != null) root.SetActive(true);

        SyncAllEntries();
        RebuildVisible();
        RefreshTabHighlights();

        SelectFirst();
    }

    public void Close()
    {
        _isOpen = false;
        if (root != null)       root.SetActive(false);
        if (lockedRoot != null) lockedRoot.SetActive(false);

        // Task 16: parar o Jukebox e devolver a BGM ao estado anterior ao fechar.
        _source.Stop();
        _isPlaying = false;
        ReleaseBgmOwnership();

        PlaySfx(toggleSfx);
        Closed?.Invoke();
    }

    public void OnCancel(BaseEventData eventData) => Close();

    // ═══════════════════════════════════════════════════════════════════════
    // Abas (L / R)
    // ═══════════════════════════════════════════════════════════════════════

    private void OnTabPrev(InputAction.CallbackContext _)
    {
        if (!_isOpen) return;
        if (_currentTab == JukeboxTab.Normal) return;

        _currentTab = JukeboxTab.Normal;
        RebuildVisible();
        RefreshTabHighlights();
        SelectFirst();
        PlaySfx(tabSwitchSfx);
    }

    private void OnTabNext(InputAction.CallbackContext _)
    {
        if (!_isOpen) return;
        if (_currentTab == JukeboxTab.Favorites) return;

        _currentTab = JukeboxTab.Favorites;
        RebuildVisible();
        RefreshTabHighlights();
        SelectFirst();
        PlaySfx(tabSwitchSfx);
    }

    private void RefreshTabHighlights()
    {
        bool normal = _currentTab == JukeboxTab.Normal;
        if (normalTabHighlight != null)    normalTabHighlight.SetActive(normal);
        if (favoritesTabHighlight != null) favoritesTabHighlight.SetActive(!normal);
    }

    // ═══════════════════════════════════════════════════════════════════════
    // Melodias Selvagens — actualização em tempo real
    // ═══════════════════════════════════════════════════════════════════════

    private void HandleMelodyCollected(WildMelodyData melody)
    {
        if (!_isOpen || !IsUnlocked) return;

        // Só reconstruir se a melodia for nova na lista.
        foreach (var e in _allEntries)
            if (e.id == melody.melodyId) return;

        SyncAllEntries();
        RebuildVisible();
    }

    // ═══════════════════════════════════════════════════════════════════════
    // Construção das listas
    // ═══════════════════════════════════════════════════════════════════════

    /// <summary>Reconstrói <see cref="_allEntries"/> a partir das faixas estáticas e wild melodies recolhidas.</summary>
    private void SyncAllEntries()
    {
        _allEntries.Clear();

        // Faixas estáticas
        var pp = PlayerProgress.Instance;
        foreach (var t in tracks)
        {
            if (t == null) continue;

            // Se tiver melodyId, só aparece após ser recolhida.
            if (!string.IsNullOrEmpty(t.melodyId) &&
                (pp == null || !pp.HasCollectedMelody(t.melodyId)))
                continue;

            _allEntries.Add(new DisplayEntry
            {
                id    = t.GetId(),
                clip  = t.clip,
                name  = t.GetDisplayName(),
                world = t.world
            });
        }

        // Wild melodies recolhidas
        if (pp != null && knownMelodies != null)
        {
            foreach (var m in knownMelodies)
            {
                if (m == null || !pp.HasCollectedMelody(m.melodyId)) continue;
                _allEntries.Add(new DisplayEntry
                {
                    id    = m.melodyId,
                    clip  = m.clip,
                    name  = string.IsNullOrEmpty(m.displayName) ? m.melodyId : m.displayName,
                    world = m.area?.world
                });
            }
        }
    }

    /// <summary>
    /// Reconstrói <see cref="_visibleEntries"/> e redesenha os botões de acordo com
    /// <see cref="_currentTab"/>.
    /// </summary>
    private void RebuildVisible()
    {
        _visibleEntries.Clear();
        ClearSpawned();

        var vars = GameVariables.Instance;

        if (_currentTab == JukeboxTab.Favorites)
        {
            // Aba Favoritos: mostrar apenas entradas marcadas como favoritas.
            foreach (var e in _allEntries)
                if (vars != null && vars.GetBool(FavKey(e.id)))
                    _visibleEntries.Add(e);

            SpawnSection(favoritesSectionLabel, _visibleEntries, vars);
        }
        else
        {
            // Aba Normal: agrupar por mundo.
            // 1. Secção de trilha sonora (faixas sem mundo).
            var staticEntries = new List<DisplayEntry>();
            foreach (var e in _allEntries)
                if (e.world == null) staticEntries.Add(e);

            if (staticEntries.Count > 0)
            {
                foreach (var e in staticEntries) _visibleEntries.Add(e);
                SpawnSection(staticSectionLabel, staticEntries, vars);
            }

            // 2. Agrupar os restantes por mundo.
            var byWorld = new Dictionary<WorldData, List<DisplayEntry>>();
            var worldOrder = new List<WorldData>();

            foreach (var e in _allEntries)
            {
                if (e.world == null) continue;
                if (!byWorld.ContainsKey(e.world))
                {
                    byWorld[e.world] = new List<DisplayEntry>();
                    worldOrder.Add(e.world);
                }
                byWorld[e.world].Add(e);
            }

            foreach (var world in worldOrder)
            {
                var entries = byWorld[world];
                foreach (var e in entries) _visibleEntries.Add(e);

                string label = string.IsNullOrEmpty(world.displayName) ? world.worldId : world.displayName;
                SpawnSection(label, entries, vars);
            }

            // 3. Wild melodies sem mundo.
            var unknownEntries = new List<DisplayEntry>();
            foreach (var e in _allEntries)
            {
                if (e.world != null) continue;
                // Não duplicar com as estáticas.
                bool isStatic = false;
                foreach (var s in staticEntries) if (s == e) { isStatic = true; break; }
                if (!isStatic) unknownEntries.Add(e);
            }

            if (unknownEntries.Count > 0)
            {
                foreach (var e in unknownEntries) _visibleEntries.Add(e);
                SpawnSection(unknownSectionLabel, unknownEntries, vars);
            }
        }

        RefreshNowPlaying();
    }

    /// <summary>
    /// Activa um cabeçalho e os botões de faixa para uma lista de entradas,
    /// reutilizando objectos já criados (Task #29 — pool). Novos objectos só
    /// são instanciados quando a pool estiver esgotada. Botões da pool têm
    /// Clicked/FavoriteClicked subscritos uma única vez na criação.
    /// </summary>
    private void SpawnSection(string sectionName, List<DisplayEntry> entries, GameVariables vars)
    {
        if (entries.Count == 0) return;

        // Cabeçalho — retirar da pool ou criar novo.
        if (sectionHeaderPrefab != null && trackContainer != null)
        {
            // Encontrar um header desactivado na pool.
            GameObject header = null;
            foreach (var h in _headerPool)
            {
                if (h != null && !h.activeSelf) { header = h; break; }
            }
            if (header == null)
            {
                header = Instantiate(sectionHeaderPrefab, trackContainer);
                _headerPool.Add(header);
            }

            header.transform.SetAsLastSibling();
            header.SetActive(true);
            _spawnedHeaders.Add(header);

            // Procurar TMP_Text no raiz ou no primeiro filho chamado "Label".
            var label = header.GetComponent<TMP_Text>();
            if (label == null)
            {
                var child = header.transform.Find("Label");
                if (child != null) label = child.GetComponent<TMP_Text>();
            }
            if (label != null) label.text = sectionName;
        }

        // Botões de faixa — retirar da pool ou criar novos.
        foreach (var entry in entries)
        {
            int  visibleIndex = _visibleEntries.IndexOf(entry);
            bool isPlaying    = _allEntries.IndexOf(entry) == _currentIndex && _isPlaying;
            bool isFavorite   = vars != null && vars.GetBool(FavKey(entry.id));

            // Encontrar um botão desactivado na pool.
            JukeboxTrackButtonUI btn = null;
            foreach (var b in _buttonPool)
            {
                if (b != null && !b.gameObject.activeSelf) { btn = b; break; }
            }
            if (btn == null)
            {
                btn = Instantiate(trackButtonPrefab, trackContainer);
                // Subscrevia UMA VEZ: a pool reutiliza o mesmo handler para sempre.
                btn.Clicked         += OnTrackClicked;
                btn.FavoriteClicked += OnFavoriteClicked;
                _buttonPool.Add(btn);
            }

            btn.transform.SetAsLastSibling();
            btn.gameObject.SetActive(true);
            btn.Setup(visibleIndex, entry.name, isPlaying, isFavorite);
            _spawned.Add(btn);
        }
    }

    /// <summary>
    /// Desactiva os botões e headers visíveis (Task #29: não destroys, apenas
    /// SetActive false). Os objectos ficam na pool para reutilização.
    /// </summary>
    private void ClearSpawned()
    {
        foreach (var btn in _spawned)
            if (btn != null) btn.gameObject.SetActive(false);
        _spawned.Clear();

        foreach (var h in _spawnedHeaders)
            if (h != null) h.SetActive(false);
        _spawnedHeaders.Clear();
    }

    // ═══════════════════════════════════════════════════════════════════════
    // Interacção — Play / Stop / Favorito
    // ═══════════════════════════════════════════════════════════════════════

    private void OnTrackClicked(JukeboxTrackButtonUI btn)
    {
        // Índice na lista visível → índice na lista completa.
        if (btn.Index < 0 || btn.Index >= _visibleEntries.Count) return;
        var entry      = _visibleEntries[btn.Index];
        int allIndex   = _allEntries.IndexOf(entry);

        if (allIndex == _currentIndex)
        {
            // Mesma faixa: toggle play/pause.
            TogglePlayPause();
        }
        else
        {
            // Faixa diferente: iniciar.
            PlayEntry(allIndex);
        }

        PlaySfx(toggleSfx);
    }

    private void OnFavoriteClicked(JukeboxTrackButtonUI btn)
    {
        if (btn.Index < 0 || btn.Index >= _visibleEntries.Count) return;
        var entry = _visibleEntries[btn.Index];
        ToggleFavorite(entry, btn);
    }

    // ═══════════════════════════════════════════════════════════════════════
    // Reprodução
    // ═══════════════════════════════════════════════════════════════════════

    /// <summary>Inicia a faixa no índice de <see cref="_allEntries"/>.</summary>
    private void PlayEntry(int allIndex)
    {
        if (_allEntries.Count == 0) return;
        allIndex = ((allIndex % _allEntries.Count) + _allEntries.Count) % _allEntries.Count;

        var entry = _allEntries[allIndex];
        _currentIndex = allIndex;
        _isPlaying    = entry.clip != null;

        // Task 16: assumir ownership do BGM ao iniciar a reprodução —
        // guarda o clip actual e para a BGM para evitar duas faixas simultâneas.
        if (_isPlaying) AcquireBgmOwnership();

        _source.clip = entry.clip;
        ApplyVolume();

        if (_isPlaying) _source.Play();
        else            _source.Stop();

        RefreshAllButtons();
        RefreshNowPlaying();
    }

    private void AcquireBgmOwnership()
    {
        if (_bgmOwned) return;
        var am = AudioManager.Instance;
        if (am == null) return;
        _savedBgmClip = am.CurrentBgmClip;
        _bgmOwned = true;
        am.StopBGM(0.5f);
    }

    private void ReleaseBgmOwnership()
    {
        if (!_bgmOwned) return;
        _bgmOwned = false;
        var am = AudioManager.Instance;
        if (am == null) return;
        if (_savedBgmClip != null)
            am.PlayBGM(_savedBgmClip);
        _savedBgmClip = null;
    }

    private void TogglePlayPause()
    {
        if (_currentIndex < 0)
        {
            if (_allEntries.Count > 0) PlayEntry(0);
            return;
        }

        if (_isPlaying)
        {
            _source.Pause();
            _isPlaying = false;
            // Ao pausar o Jukebox, devolver o ownership da BGM
            // para que a música da área retome enquanto o Jukebox está em pausa.
            ReleaseBgmOwnership();
        }
        else
        {
            _source.UnPause();
            if (!_source.isPlaying && _source.clip != null) _source.Play();
            _isPlaying = true;
            AcquireBgmOwnership();
        }

        RefreshAllButtons();
        RefreshNowPlaying();
    }

    // ═══════════════════════════════════════════════════════════════════════
    // Favoritos
    // ═══════════════════════════════════════════════════════════════════════

    private void ToggleFavorite(DisplayEntry entry, JukeboxTrackButtonUI btn)
    {
        var vars = GameVariables.Instance;
        if (vars == null) return;

        string key = FavKey(entry.id);
        bool current = vars.GetBool(key);
        vars.SetBool(key, !current);

        btn.SetFavorite(!current);
        PlaySfx(favoriteSfx);

        // Na aba de Favoritos, remover imediatamente se desfavoritado.
        if (_currentTab == JukeboxTab.Favorites && current)
            RebuildVisible();
    }

