    /// <summary>Actualiza todos os botões instanciados para reflectir a faixa actualmente a tocar.</summary>
    private void RefreshAllButtons()
    {
        var vars = GameVariables.Instance;

        for (int i = 0; i < _spawned.Count; i++)
        {
            if (_spawned[i] == null) continue;

            int visibleIndex = _spawned[i].Index;
            if (visibleIndex < 0 || visibleIndex >= _visibleEntries.Count) continue;

            var entry = _visibleEntries[visibleIndex];
            int allIndex = _allEntries.IndexOf(entry);

            bool isPlaying  = (allIndex == _currentIndex) && _isPlaying;
            bool isFavorite = vars != null && vars.GetBool(FavKey(entry.id));

            _spawned[i].SetPlaying(isPlaying);
            _spawned[i].SetFavorite(isFavorite);
        }
    }

    private void RefreshNowPlaying()
    {
        if (nowPlayingText == null) return;

        if (_currentIndex < 0 || _currentIndex >= _allEntries.Count || !_isPlaying)
        {
            nowPlayingText.text = noTracksText;
            return;
        }

        nowPlayingText.text = _allEntries[_currentIndex].name;
    }

    private void SelectFirst()
    {
        if (EventSystem.current == null) return;

        if (_spawned.Count > 0 && _spawned[0] != null)
            EventSystem.current.SetSelectedGameObject(_spawned[0].gameObject);
        else if (firstSelectable != null)
            EventSystem.current.SetSelectedGameObject(firstSelectable.gameObject);
    }

    private void PlaySfx(AudioClip clip)
    {
        if (clip != null) AudioManager.Instance?.PlaySE(clip);
    }
